private String executePost(String targetURL, String urlParameters) {
    URL url;
    HttpURLConnection connection = null;
    try {
        url = new URL(targetURL);
        connection = (HttpURLConnection) url.openConnection();
        connection.setRequestMethod("POST");
        connection.setRequestProperty("Content-Type", "application/x-www-form-urlencoded");
        connection.setRequestProperty("Content-Length", "" + Integer.toString(urlParameters.getBytes().length));
        connection.setRequestProperty("Content-Language", "en-US");
        connection.setUseCaches(false);
        connection.setDoInput(true);
        connection.setDoOutput(true);
        DataOutputStream wr = new DataOutputStream(connection.getOutputStream());
        wr.writeBytes(urlParameters);
        wr.flush();
        wr.close();
        InputStream is = connection.getInputStream();
        BufferedReader rd = new BufferedReader(new InputStreamReader(is));
        String line;
        StringBuffer response = new StringBuffer();
        while ((line = rd.readLine()) != null) {
            response.append(line);
            response.append('\r');
        }
        rd.close();
        return response.toString();
    } catch (Exception e) {
        e.printStackTrace();
        return null;
    } finally {
        if (connection != null) {
            connection.disconnect();
        }
    }
}

private String postXml(String url, String soapAction, String xml) {
    try {
        URLConnection conn = new URL(url).openConnection();
        if (conn instanceof HttpURLConnection) {
            HttpURLConnection hConn = (HttpURLConnection) conn;
            hConn.setRequestMethod("POST");
        }
        conn.setConnectTimeout(this.connectionTimeout);
        conn.setReadTimeout(this.connectionTimeout);
        conn.setRequestProperty("Content-Type", "text/xml; charset=utf-8");
        conn.setRequestProperty("Accept", "application/soap+xml, text/*");
        if (soapAction != null) {
            conn.setRequestProperty("SOAPAction", soapAction);
        }
        conn.setDoOutput(true);
        OutputStreamWriter out = new OutputStreamWriter(conn.getOutputStream());
        out.write(xml);
        out.close();
        BufferedReader resp = new BufferedReader(new InputStreamReader(conn.getInputStream()));
        StringBuilder buf = new StringBuilder();
        String str;
        while ((str = resp.readLine()) != null) {
            buf.append(str);
        }
        return buf.toString();
    } catch (IOException e) {
        throw new RuntimeException(e);
    }
}

public User getUser(String userlogin) {
    UserDAO userDAO = new UserDAO();
