            if (iOpenBody < 0) iOpenBody = sTransformed.indexOf("<BODY", iCloseHead);
            iCloseBody = sTransformed.indexOf(">", iOpenBody + 5);
            for (char s = sTransformed.charAt(iCloseBody + 1); s == '\r' || s == '\n' || s == ' ' || s == '\t'; s = sTransformed.charAt(++iCloseBody)) ;
